import{_ as e,o as t,c as s,a4 as o}from"./chunks/framework.4M7SpZrd.js";const u=JSON.parse('{"title":"KAAS — Kubex Agent-as-a-Service","description":"","frontmatter":{},"headers":[],"relativePath":"agentes/index.md","filePath":"agentes/index.md"}'),n={name:"agentes/index.md"};function r(i,a,d,l,c,p){return t(),s("div",null,[...a[0]||(a[0]=[o(`<h1 id="kaas-—-kubex-agent-as-a-service" tabindex="-1">KAAS — Kubex Agent-as-a-Service <a class="header-anchor" href="#kaas-—-kubex-agent-as-a-service" aria-label="Permalink to &quot;KAAS — Kubex Agent-as-a-Service&quot;">​</a></h1><p>Sistema de agentes IA que gerenciam o Kubex sob demanda, operando como &quot;gerentes de departamento&quot; sob supervisao do CEO.</p><hr><h2 id="o-que-e-o-kaas" tabindex="-1">O que e o KAAS? <a class="header-anchor" href="#o-que-e-o-kaas" aria-label="Permalink to &quot;O que e o KAAS?&quot;">​</a></h2><p>O KAAS (Kubex Agent-as-a-Service) e um framework de agentes IA construido sobre o <a href="https://github.com/anthropics/aiox-core" target="_blank" rel="noreferrer">AIOX-Core</a> que automatiza a operacao, monitoramento, seguranca e melhoria continua da plataforma Kubex.</p><p>Cada agente e uma <strong>persona especializada</strong> que roda dentro do Claude Code (VSCode), com regras, permissoes e workflows definidos.</p><h3 id="principios" tabindex="-1">Principios <a class="header-anchor" href="#principios" aria-label="Permalink to &quot;Principios&quot;">​</a></h3><ul><li><strong>Hibrido</strong> — 8 agentes automaticos via scheduler + 3 sob demanda pelo CEO</li><li><strong>Economia de tokens</strong> — contexto enxuto, rules consolidadas, execucao focada</li><li><strong>Seguranca primeiro</strong> — OWASP Top 10 + LGPD compliance obrigatorios</li><li><strong>Observabilidade</strong> — toda acao registrada e auditavel</li><li><strong>Foco &gt; volume</strong> — max 3 melhorias por ciclo de execucao</li></ul><hr><h2 id="documentacao" tabindex="-1">Documentacao <a class="header-anchor" href="#documentacao" aria-label="Permalink to &quot;Documentacao&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Documento</th><th>Descricao</th></tr></thead><tbody><tr><td><a href="./tecnicas-avancadas">T0-T11: Técnicas Avançadas</a></td><td>✨ 11 técnicas de otimização para performance e inteligência</td></tr><tr><td><a href="./dynamic-skills">Dynamic Skills System</a></td><td>✨ NOVO — Agentes escolhem skills dinamicamente (T4 implementation)</td></tr><tr><td><a href="./scheduler">KAAS Scheduler — Ativação</a></td><td>Como iniciar e operar o scheduler automático</td></tr><tr><td><a href="./quick-start">KAAS em 5 Minutos</a></td><td>Guia rapido para iniciantes — do zero ao primeiro agente</td></tr><tr><td><a href="./fluxos">Fluxos e Diagramas</a></td><td>Fluxogramas visuais de como os agentes interagem</td></tr><tr><td><a href="./exemplos">Exemplos de Sessoes</a></td><td>Logs reais mostrando input/output de cada agente</td></tr><tr><td><a href="./faq">FAQ — Perguntas Frequentes</a></td><td>Respostas para duvidas comuns sobre operacao</td></tr><tr><td><a href="/takedown-docs/agentes/operacao">Operacao Completa</a></td><td>Guia tecnico completo (instalacao, comandos, troubleshooting)</td></tr></tbody></table><hr><h2 id="agentes" tabindex="-1">Agentes <a class="header-anchor" href="#agentes" aria-label="Permalink to &quot;Agentes&quot;">​</a></h2><p>11 agentes: <strong>8 automaticos</strong> (rodam em schedule via KAAS Scheduler) + <strong>3 sob demanda</strong> (CEO aciona via dashboard ou Claude Code).</p><table tabindex="0"><thead><tr><th>Agente</th><th>Persona</th><th>Papel</th><th>Modo</th><th>Quando acionar</th></tr></thead><tbody><tr><td><strong>SRE Agent</strong></td><td>Polaris</td><td>Saude dos 27 motores, health checks, circuit breakers</td><td>Automático (2h)</td><td>—</td></tr><tr><td><strong>QA Agent</strong> ✨</td><td>Capella</td><td>Testes, cobertura, regressoes, linting</td><td>Automático (4h)</td><td>—</td></tr><tr><td><strong>Security Agent</strong></td><td>Sirius</td><td>OWASP Top 10, LGPD audit, scan de dependencias</td><td>Automático (1x/semana seg)</td><td>—</td></tr><tr><td><strong>Infra Agent</strong></td><td>Atlas</td><td>Docker, Nginx, volumes, networking health</td><td>Automático (1x/dia)</td><td>—</td></tr><tr><td><strong>DBA Agent</strong></td><td>Rigel</td><td>PostgreSQL, Redis, Milvus, MinIO health</td><td>Automático (1x/dia)</td><td>—</td></tr><tr><td><strong>Docs Agent</strong></td><td>Aquila</td><td>VitePress, Swagger, docstrings, changelog</td><td>Automático (6h)</td><td>—</td></tr><tr><td><strong>Director Agent</strong></td><td>Vega</td><td>Orquestra agentes, prioriza backlog, relatorios</td><td>Automático (2x/dia + semanal)</td><td>—</td></tr><tr><td><strong>Face Crawl Agent</strong> ✨</td><td>Fomalhaut</td><td>Auditoria pipeline de face crawling</td><td>Automático (1x/semana seg)</td><td>—</td></tr><tr><td><strong>Backend Agent</strong></td><td>Altair</td><td>Correcoes, melhorias, refatoracoes</td><td>Sob demanda</td><td>Quando ha bugs ou melhorias aprovadas</td></tr><tr><td><strong>Frontend Agent</strong></td><td>Deneb</td><td>Builds, TypeScript, design system, performance</td><td>Sob demanda</td><td>UX implementation e audits</td></tr><tr><td><strong>UX Agent</strong></td><td>Procyon</td><td>Auditorias UX/UI, design consistency, acessibilidade</td><td>Sob demanda</td><td>Antes de features visuais, design reviews</td></tr></tbody></table><hr><h2 id="personas-estelares" tabindex="-1">Personas Estelares <a class="header-anchor" href="#personas-estelares" aria-label="Permalink to &quot;Personas Estelares&quot;">​</a></h2><p>Cada agente possui um nome de persona inspirado em estrelas e constelacoes:</p><ul><li><strong>Polaris</strong> — A Sentinela (SRE) — Fixa, sempre vigiando os motores</li><li><strong>Rigel</strong> — O Arquivista (DBA) — Guardiao confiavel de dados</li><li><strong>Sirius</strong> — A Guardia (Security) — Poderosa e vigilante</li><li><strong>Vega</strong> — A Comandante (Director) — Lider estrategica</li><li><strong>Capella</strong> — A Inspetora (QA) — Precisao em cada detalhe</li><li><strong>Atlas</strong> — O Construtor (Infra) — Sustenta a base de tudo</li><li><strong>Altair</strong> — O Engenheiro (Backend) — Processamento intenso</li><li><strong>Deneb</strong> — O Artesao (Frontend) — Cria interfaces deslumbrantes</li><li><strong>Aquila</strong> — A Escriba (Docs) — Comunica conhecimento</li><li><strong>Fomalhaut</strong> — O Rastreador (Face Crawl) — Auditoria do pipeline facial</li><li><strong>Procyon</strong> — A Designer (UX) — Cria experiencias belas e funcionais</li></ul><hr><h2 id="hierarquia" tabindex="-1">Hierarquia <a class="header-anchor" href="#hierarquia" aria-label="Permalink to &quot;Hierarquia&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CEO (Renato)</span></span>
<span class="line"><span>  └── Director Agent (orquestrador)</span></span>
<span class="line"><span>        ├── SRE Agent      ├── DBA Agent</span></span>
<span class="line"><span>        ├── Security Agent  ├── Infra Agent</span></span>
<span class="line"><span>        ├── QA Agent        ├── Face Crawl Agent</span></span>
<span class="line"><span>        ├── Backend Agent   ├── Frontend Agent</span></span>
<span class="line"><span>        ├── Docs Agent      └── UX Agent</span></span></code></pre></div><p><strong>Regras de ouro:</strong></p><ol><li>Agentes <strong>NUNCA</strong> fazem merge em <code>main</code> sem aprovacao do CEO</li><li>Agentes <strong>NUNCA</strong> editam <code>.env</code>, credentials ou <code>docker-compose.yml</code> (prod)</li><li>Agentes <strong>SEMPRE</strong> criam branches <code>kaas/{agente}/{descricao}</code></li><li>Operacoes destrutivas requerem aprovacao do CEO</li></ol><hr><h2 id="arquivos-do-framework" tabindex="-1">Arquivos do Framework <a class="header-anchor" href="#arquivos-do-framework" aria-label="Permalink to &quot;Arquivos do Framework&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.aiox-core/</span></span>
<span class="line"><span>├── personas/kubex/          # 11 personas de agentes</span></span>
<span class="line"><span>├── skills/kubex/            # 8 skills customizadas</span></span>
<span class="line"><span>├── workflows/kubex/         # 3 workflows</span></span>
<span class="line"><span>├── rules/kubex-operations.md</span></span>
<span class="line"><span>└── [core AIOX files...]     # Framework base</span></span>
<span class="line"><span></span></span>
<span class="line"><span>.claude/</span></span>
<span class="line"><span>├── rules/                   # 2 regras consolidadas</span></span>
<span class="line"><span>│   ├── agent-operations.md  # Autoridade, ciclo, escalonamento</span></span>
<span class="line"><span>│   └── compliance-review.md # Seguranca, LGPD, code review</span></span>
<span class="line"><span>└── CLAUDE.md                # Configuracao do framework</span></span>
<span class="line"><span></span></span>
<span class="line"><span>docs/agentes/                # Esta documentacao</span></span></code></pre></div><hr><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><ul><li><a href="./scheduler">KAAS Scheduler — Como Iniciar</a></li><li><a href="./quick-start">Guia Rapido (5 min)</a></li><li><a href="./fluxos">Fluxos e Diagramas</a></li><li><a href="./faq">FAQ</a></li><li><a href="./operacao">Guia Operacional Completo</a></li></ul>`,30)])])}const m=e(n,[["render",r]]);export{u as __pageData,m as default};
